mapper.select:
/* SQL ID : SysMenuDAO.list 설 명 : 시스템 메뉴의 전체 목록 */
SELECT A.MENU_ID as menuCd , A.MENU_TYCD as menuType , A.UP_MENU_ID as parMenuCd , A.MENU_LV as menuLvl , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END as parMenuLvl , A.MENU_SEQ as menuOdr , A.MENU_URL as menuUrl , A.MENU_PATH as menuPath , A.USEYN as useYn , A.UPEND_MENUYN as topMenuYn , A.TOP_MENU_IMG as topMenuImg , A.LEFT_SIDE_MENU_IMG as leftMenuImg , A.LEFT_SIDE_MENU_TTL as leftMenuTitle , A.MENU_TTL as menuTitle , A.BRDRLN_USEYN as divLineUseYn , A.OPTN_CTGR_CD_1 as optnCtgrId1 , A.OPTN_CD_1 as optnCd1 , A.OPTN_CTGR_CD_2 as optnCtgrCd2 , A.OPTN_CD_2 as optnCd2 , A.OPTN_CTGR_CD_3 as optnCtgrCd3 , A.OPTN_CD_3 as optnCd3 , A.OPTN_CTGR_CD_4 as optnCtgrCd4 , A.OPTN_CD_4 as optnCd4 , A.OPTN_CTGR_CD_5 as optnCtgrCd5 , A.OPTN_CD_5 as optnCd5 , A.SSL_USEYN as sslYn , A.RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS regNm , A.FRST_INQ_DTTM as regDttm , A.MDFR_ID as mdfrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS modNm , A.MOD_DTTM as modDttm , IFNULL(B.VIEW_AUTH,'N') AS viewAuth , IFNULL(B.REG_AUTHRTYN,'N') AS creAuth , IFNULL(B.MOD_AUTHRTYN,'N') AS modAuth , IFNULL(B.DEL_AUTH,'N') AS delAuth , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS subCnt FROM TB_LMS_MENU A LEFT OUTER JOIN tb_sys_auth_grp_menu B ON A.MENU_TYCD = B.MENU_TYCD AND A.MENU_ID = B.MENU_ID WHERE 1=1
AND A.MENU_TYCD = #{menuType} AND B.USER_AUTHRT_ID(+) = #{authGrpCd}
AND A.USEYN = #{useYn}
AND A.UP_MENU_ID = #{parMenuCd}
ORDER BY A.MENU_SEQ

/* SQL ID : SysMenuDAO.select 설 명 : 시스템 메뉴의 정보 조회 */
SELECT A.MENU_ID as menuCd , A.MENU_TYCD as menuType , A.UP_MENU_ID as parMenuCd , A.MENU_LV as menuLvl , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END as parMenuLvl , A.MENU_SEQ as menuOdr , A.MENU_URL as menuUrl , A.MENU_PATH as menuPath , A.USEYN as useYn , A.UPEND_MENUYN as topMenuYn , A.TOP_MENU_IMG as topMenuImg , A.LEFT_SIDE_MENU_IMG as leftMenuImg , A.LEFT_SIDE_MENU_TTL as leftMenuTitle , A.MENU_TTL as menuTitle , A.BRDRLN_USEYN as divLineUseYn , A.OPTN_CTGR_CD_1 as optnCtgrId1 , A.OPTN_CD_1 as optnCd1 , A.OPTN_CTGR_CD_2 as optnCtgrCd2 , A.OPTN_CD_2 as optnCd2 , A.OPTN_CTGR_CD_3 as optnCtgrCd3 , A.OPTN_CD_3 as optnCd3 , A.OPTN_CTGR_CD_4 as optnCtgrCd4 , A.OPTN_CD_4 as optnCd4 , A.OPTN_CTGR_CD_5 as optnCtgrCd5 , A.OPTN_CD_5 as optnCd5 , A.SSL_USEYN as sslYn , A.RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS regNm , A.FRST_INQ_DTTM as regDttm , A.MDFR_ID as mdfrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS modNm , A.MOD_DTTM as modDttm , IFNULL(B.VIEW_AUTH,'N') AS viewAuth , IFNULL(B.REG_AUTHRTYN,'N') AS creAuth , IFNULL(B.MOD_AUTHRTYN,'N') AS modAuth , IFNULL(B.DEL_AUTH,'N') AS delAuth , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS subCnt FROM TB_LMS_MENU A LEFT OUTER JOIN tb_sys_auth_grp_menu B ON A.MENU_TYCD = B.MENU_TYCD AND A.MENU_ID = B.MENU_ID WHERE 1=1
AND A.MENU_TYCD = #{menuType} AND B.USER_AUTHRT_ID(+) = #{authGrpCd} AND A.MENU_ID = #{menuCd}

/* SQL ID : SysMenuDAO.listByAuth 설 명 : 권한 그룹별 메뉴 목록 */
SELECT A.MENU_ID as menuCd , A.MENU_TYCD as menuType , A.UP_MENU_ID as parMenuCd , A.MENU_LV as menuLvl , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END as parMenuLvl , A.MENU_SEQ as menuOdr , A.MENU_URL as menuUrl , A.MENU_PATH as menuPath , A.USEYN as useYn , A.UPEND_MENUYN as topMenuYn , A.TOP_MENU_IMG as topMenuImg , A.LEFT_SIDE_MENU_IMG as leftMenuImg , A.LEFT_SIDE_MENU_TTL as leftMenuTitle , A.MENU_TTL as menuTitle , A.BRDRLN_USEYN as divLineUseYn , A.OPTN_CTGR_CD_1 as optnCtgrId1 , A.OPTN_CD_1 as optnCd1 , A.OPTN_CTGR_CD_2 as optnCtgrCd2 , A.OPTN_CD_2 as optnCd2 , A.OPTN_CTGR_CD_3 as optnCtgrCd3 , A.OPTN_CD_3 as optnCd3 , A.OPTN_CTGR_CD_4 as optnCtgrCd4 , A.OPTN_CD_4 as optnCd4 , A.OPTN_CTGR_CD_5 as optnCtgrCd5 , A.OPTN_CD_5 as optnCd5 , A.SSL_USEYN as sslYn , A.RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS regNm , A.FRST_INQ_DTTM as regDttm , A.MDFR_ID as mdfrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS modNm , A.MOD_DTTM as modDttm , IFNULL(B.VIEW_AUTH,'N') AS viewAuth , IFNULL(B.REG_AUTHRTYN,'N') AS creAuth , IFNULL(B.MOD_AUTHRTYN,'N') AS modAuth , IFNULL(B.DEL_AUTH,'N') AS delAuth , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS subCnt FROM TB_LMS_MENU A LEFT OUTER JOIN tb_sys_auth_grp_menu B ON A.MENU_TYCD = B.MENU_TYCD AND A.MENU_ID = B.MENU_ID WHERE 1=1
AND A.MENU_TYCD = #{menuType} AND #{authGrpCd} LIKE CONCAT('%',B.USER_AUTHRT_ID,'%') COLLATE utf8mb4_general_ci AND A.USEYN = 'Y' ORDER BY A.MENU_SEQ

/* SQL ID : SysMenuDAO.selectByUser 설 명 : 권한 그룹별 시스템 메뉴의 정보 조회 */
SELECT A.MENU_ID as menuCd , A.MENU_TYCD as menuType , A.UP_MENU_ID as parMenuCd , A.MENU_LV as menuLvl , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END as parMenuLvl , A.MENU_SEQ as menuOdr , A.MENU_URL as menuUrl , A.MENU_PATH as menuPath , A.USEYN as useYn , A.UPEND_MENUYN as topMenuYn , A.TOP_MENU_IMG as topMenuImg , A.LEFT_SIDE_MENU_IMG as leftMenuImg , A.LEFT_SIDE_MENU_TTL as leftMenuTitle , A.MENU_TTL as menuTitle , A.BRDRLN_USEYN as divLineUseYn , A.OPTN_CTGR_CD_1 as optnCtgrId1 , A.OPTN_CD_1 as optnCd1 , A.OPTN_CTGR_CD_2 as optnCtgrCd2 , A.OPTN_CD_2 as optnCd2 , A.OPTN_CTGR_CD_3 as optnCtgrCd3 , A.OPTN_CD_3 as optnCd3 , A.OPTN_CTGR_CD_4 as optnCtgrCd4 , A.OPTN_CD_4 as optnCd4 , A.OPTN_CTGR_CD_5 as optnCtgrCd5 , A.OPTN_CD_5 as optnCd5 , A.SSL_USEYN as sslYn , A.RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS regNm , A.FRST_INQ_DTTM as regDttm , A.MDFR_ID as mdfrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS modNm , A.MOD_DTTM as modDttm , IFNULL(B.VIEW_AUTH,'N') AS viewAuth , IFNULL(B.REG_AUTHRTYN,'N') AS creAuth , IFNULL(B.MOD_AUTHRTYN,'N') AS modAuth , IFNULL(B.DEL_AUTH,'N') AS delAuth , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS subCnt FROM TB_LMS_MENU A LEFT OUTER JOIN tb_sys_auth_grp_menu B ON A.MENU_TYCD = B.MENU_TYCD AND A.MENU_ID = B.MENU_ID WHERE 1=1
AND #{authGrpCd} LIKE CONCAT('%',B.USER_AUTHRT_ID,'%') COLLATE utf8mb4_general_ci AND A.USEYN = 'Y' AND A.MENU_ID = #{menuCd}

mapper.insert:
	/*
		 SQL ID : SysMenuDAO.insert
		 설  명 : 시스템 메뉴의 정보 등록
 	*/
	INSERT INTO TB_LMS_MENU (
	       MENU_ID
	     , MENU_TYCD
	     , MENUNM
	     , UP_MENU_ID
	     , MENU_LV
	     , MENU_SEQ
	     , MENU_URL
	     , MENU_PATH
	     , MENU_EXPLN
	     , USEYN
	     , UPEND_MENUYN
	     , TOP_MENU_IMG
	     , LEFT_SIDE_MENU_IMG
	     , LEFT_SIDE_MENU_TTL
	     , MENU_TTL
	     , BRDRLN_USEYN
	     , OPTN_CTGR_CD_1
	     , OPTN_CD_1
	     , OPTN_CTGR_CD_2
	     , OPTN_CD_2
	     , OPTN_CTGR_CD_3
	     , OPTN_CD_3
	     , OPTN_CTGR_CD_4
	     , OPTN_CD_4
	     , OPTN_CTGR_CD_5
	     , OPTN_CD_5
	     , SSL_USEYN
	     , RGTR_ID
	     , FRST_INQ_DTTM
	     , MDFR_ID
	     , MOD_DTTM
	) VALUES (
		   #{menuCd}
	     , #{menuType}
	     , #{menuNm}
	     , #{parMenuCd}
	     , #{menuLvl}
	     , ( SELECT IFNULL(MAX(A.MENU_SEQ),0)+1
	           FROM TB_LMS_MENU A
	          WHERE A.MENU_TYCD = #{menuType}
	            AND IFNULL(A.UP_MENU_ID,'1') = IFNULL(#{parMenuCd},'1') )
	     , #{menuUrl}
	     , #{menuPath}
	     , #{menuDesc}
	     , #{useYn}
	     , #{topMenuYn}
	     , #{topMenuImg}
	     , #{leftMenuImg}
	     , #{leftMenuTitle}
	     , #{menuTitle}
	     , #{divLineUseYn}
	     , #{optnCtgrCd1}
	     , #{optnCd1}
	     , #{optnCtgrCd2}
	     , #{optnCd2}
	     , #{optnCtgrCd3}
	     , #{optnCd3}
	     , #{optnCtgrCd4}
	     , #{optnCd4}
	     , #{optnCtgrCd5}
	     , #{optnCd5}
	     , #{sslYn}
	     , #{rgtrId}
	     , DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	     , #{mdfrId}
	     , DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	)

mapper.update:
	/*
		 SQL ID : SysMenuDAO.update
		 설  명 : 시스템 메뉴의 정보 수정
 	*/
	UPDATE TB_LMS_MENU
	   SET MENUNM = #{menuNm}
	     , UP_MENU_ID = #{parMenuCd}
	     , MENU_LV = IFNULL(( SELECT A.MENU_LV+1
	                       	  FROM TB_LMS_MENU A
	                     	 WHERE A.MENU_ID = #{parMenuCd}),1)
	     , MENU_SEQ = #{menuOdr}
	     , MENU_URL = #{menuUrl}
	     , MENU_PATH = #{menuPath}
	     , MENU_EXPLN = #{menuDesc}
	     , USEYN = #{useYn}
	     , UPEND_MENUYN = #{topMenuYn}
	     , TOP_MENU_IMG = #{topMenuImg}
	     , LEFT_SIDE_MENU_IMG = #{leftMenuImg}
	     , LEFT_SIDE_MENU_TTL = #{leftMenuTitle}
	     , MENU_TTL = #{menuTitle}
	     , BRDRLN_USEYN = #{divLineUseYn}
	     , OPTN_CTGR_CD_1 = #{optnCtgrCd1}
	     , OPTN_CD_1 = #{optnCd1}
	     , OPTN_CTGR_CD_2 = #{optnCtgrCd2}
	     , OPTN_CD_2 = #{optnCd2}
	     , OPTN_CTGR_CD_3 = #{optnCtgrCd3}
	     , OPTN_CD_3 = #{optnCd3}
	     , OPTN_CTGR_CD_4 = #{optnCtgrCd4}
	     , OPTN_CD_4 = #{optnCd4}
	     , OPTN_CTGR_CD_5 = #{optnCtgrCd5}
	     , OPTN_CD_5 = #{optnCd5}
	     , SSL_USEYN = #{sslYn}
	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	 WHERE MENU_TYCD = #{menuType}
	   AND MENU_ID = #{menuCd}

mapper.delete:
	/*
		 SQL ID : SysMenuDAO.delete
		 설  명 : 시스템 메뉴의 정보 삭제
 	*/
	DELETE FROM TB_LMS_MENU
	 WHERE MENU_TYCD = #{menuType}
	   AND MENU_ID = #{menuCd}

mapper.insert:

	/*
		 SQL ID : SysMenuDAO.insertAuthGrpMenu
		 설  명 : 권한 그룹에 권한 메뉴를 등록 한다.
 	*/
	INSERT INTO TB_SYS_AUTH_GRP_MENU (
		   MENU_TYCD
	     , MENU_ID
	     , USER_AUTHRT_ID
	     , VIEW_AUTH
	     , REG_AUTHRTYN
	     , MOD_AUTHRTYN
	     , DEL_AUTH
	     , RGTR_ID
	     , FRST_INQ_DTTM
	     , MDFR_ID
	     , MOD_DTTM
	) VALUES (
	       #{menuType}
	     , #{menuCd}
	     , #{authGrpCd}
	     , #{viewAuth}
	     , #{creAuth}
	     , #{modAuth}
	     , #{delAuth}
	     , #{rgtrId}
	     , DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	     , #{mdfrId}
	     , DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	)

mapper.update:

	/*
		 SQL ID : SysMenuDAO.updateAuthGrpMenu
		 설  명 : 권한 그룹에 권한 메뉴를 등록 한다.
 	*/
 	UPDATE TB_SYS_AUTH_GRP_MENU
 	   SET VIEW_AUTH = #{viewAuth}
	     , REG_AUTHRTYN = #{creAuth}
	     , MOD_AUTHRTYN = #{modAuth}
	     , DEL_AUTH = #{delAuth}
	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	 WHERE MENU_TYCD = #{menuType}
	   AND MENU_ID = #{menuCd}
	   AND USER_AUTHRT_ID = #{authGrpCd}

mapper.delete:
	/*
		 SQL ID : SysMenuDAO.deleteAuthGrpMenuByAuthGrp
		 설  명 : 권한 그룹에 부여된 권한 메뉴를 삭제한다.
 	*/
	DELETE FROM TB_SYS_AUTH_GRP_MENU
	 WHERE MENU_TYCD = #{menuType}
	   AND USER_AUTHRT_ID = #{authGrpCd}

	/*
		 SQL ID : SysMenuDAO.deleteAuthGrpMenuByAuthGrp
		 설  명 : 메뉴에 연결된 권한 메뉴를 삭제한다.
 	*/
	DELETE FROM TB_SYS_AUTH_GRP_MENU
	 WHERE MENU_TYCD = #{menuType}
	   AND MENU_ID = #{menuCd}

mapper.update:
	/*
		 SQL ID : SysMenuDAO.updateSysMenuListUseYn
		 설  명 : 관리자 메뉴 사용 유무 저장
 	*/
	UPDATE TB_LMS_AUTHRT
	      SET VIEW_AUTH = #{viewAuth}
	     		, MDFR_ID = #{mdfrId}
	     		, MOD_DTTM = FN_DTTM()
 	 WHERE ORG_ID = #{orgId}
	   AND MENU_TYCD = 'ADMIN'
	   AND USER_AUTHRT_ID = #{authGrpCd}
	   AND MENU_ID = #{menuCd}
